import mylib as ml

def preprocess(values: list[float], *, clip_min: float = -3.0, clip_max: float = 3.0) -> list[float]:
    """Standardize a list of numbers using z-score and clip to a range.

    The returned list is a new list and does not modify the input.

    Examples:
        >>> preprocess([1.0, 2.0, 3.0], clip_min=-1.0, clip_max=1.0)
        [-1.0, 0.0, 1.0]
        >>> preprocess([])
        []
    """
    if not values:
        return []
    mean = sum(values) / len(values)
    var = sum((x - mean) ** 2 for x in values) / len(values)
    std = var ** 0.5
    # Avoid division by zero for constant lists.
    if std == 0:
        standardized = [0.0 for _ in values]
    else:
        standardized = [(x - mean) / std for x in values]

    def _clip(x: float) -> float:
        if x < clip_min:
            return float(clip_min)
        if x > clip_max:
            return float(clip_max)
        return float(x)

    return [_clip(x) for x in standardized]
