import mylib as ml

def count_tokens(text: str) -> dict[str, int]:
    """Count whitespace-separated tokens in a string.

    Examples:
        >>> count_tokens('a b a')
        {'a': 2, 'b': 1}
    """
    counts: dict[str, int] = {}
    for tok in text.split():
        counts[tok] = counts.get(tok, 0) + 1
    return counts
